/* oms-master-renewal-directive-sql-oracle.xml - updateMstAsrtRenewal */
UPDATE TORDER_MST_ASRT SET   CMT ='Renewal Directive'
		,ASRTSTATUS = '02'
		,UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
		,UPDATEURKEY = 'MALI/F'
WHERE OWKEY = #{owkey}
  AND ASRTKEY =#{bfchgickey}

/* oms-master-renewal-directive-sql-oracle.xml - updateMstIcRenewal */
UPDATE TORDER_MST_IC M
SET   CHGBFIC  =#{bfchgickey}
	 ,CHGAFIC  =#{afchgickey}
	 ,UPDATEDATE =TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
	 ,UPDATEURKEY = 'MALI/F'
WHERE OWKEY =#{owkey}
  AND ICKEY =#{bfchgickey}
